import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { FaUserCircle } from 'react-icons/fa';
import InicioSesion from '../components/inicioSesion'; // ajusta la ruta si es necesario

const Navbar = () => {
  const navigate = useNavigate();

  const [loggedIn, setLoggedIn] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [showLogin, setShowLogin] = useState(false);

  useEffect(() => {
    setLoggedIn(localStorage.getItem("loggedIn") === "true");
  }, []);

  const handleLoginClick = () => setShowLogin(true);
  const handleCloseLogin = () => setShowLogin(false);

  const handleLoginSuccess = ({ usuario, contrasena }) => {
    localStorage.setItem("loggedIn", "true");
    setLoggedIn(true);
    setShowLogin(false);
  };

  const handleUserClick = () => setMenuOpen((prev) => !prev);

  const handleLogout = () => {
    localStorage.removeItem("loggedIn");
    setLoggedIn(false);
    setMenuOpen(false);
    navigate("/");
  };

  const links = [
    { label: "HISTORIA", path: "/historia" },
    { label: "PRESENTACIONES", path: "/presentaciones" },
    { label: "INICIO", path: "/" },
    { label: "EMPRESAS", path: "/empresas" },
    { label: "CONTACTO", path: "/contacto" },
  ];

  const styles = {
    navbar: {
      width: "100%",
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center",
      padding: "1rem 2rem",
      backgroundColor: "white",
      borderBottom: "1px solid #e5e7eb",
      position: "relative"
    },
    linksContainer: {
      display: "flex",
      gap: "1.5rem"
    },
    link: (isInicio) => ({
      fontSize: "0.875rem",
      letterSpacing: "0.1em",
      fontWeight: isInicio ? "600" : "300",
      color: "#1f2937",
      textDecoration: "none",
    }),
    userButton: {
      background: "none",
      border: "none",
      cursor: "pointer",
    },
    dropdown: {
      position: "absolute",
      top: "60px",
      right: "2rem",
      backgroundColor: "white",
      border: "1px solid #ccc",
      borderRadius: "8px",
      boxShadow: "0px 4px 6px rgba(0, 0, 0, 0.1)",
      zIndex: 1000,
      minWidth: "200px"
    },
    dropdownItem: {
      padding: "10px 16px",
      width: "100%",
      background: "none",
      border: "none",
      textAlign: "left",
      fontSize: "14px",
      cursor: "pointer",
    },
    divider: {
      height: "1px",
      backgroundColor: "#eee",
    },
  };

  return (
    <>
      <nav style={styles.navbar}>
        <div style={styles.linksContainer}>
          {links.map((item, index) => (
            <Link
              key={index}
              to={item.path}
              style={styles.link(item.label === "INICIO")}
            >
              {item.label}
            </Link>
          ))}
        </div>

        <div>
          <button
            style={styles.userButton}
            onClick={loggedIn ? handleUserClick : handleLoginClick}
            title={loggedIn ? "Panel de administrador" : "Iniciar sesión"}
          >
            <FaUserCircle size={28} color="#1f2937" />
          </button>

          {loggedIn && menuOpen && (
            <div style={styles.dropdown}>
              <button
                style={styles.dropdownItem}
                onClick={() => { navigate("/editor-empresas"); setMenuOpen(false); }}
              >
                Admin. Empresas
              </button>
              <button
                style={styles.dropdownItem}
                onClick={() => { navigate("/editor-usuarios"); setMenuOpen(false); }}
              >
                Admin. Usuarios
              </button>
              <div style={styles.divider} />
              <button
                style={{ ...styles.dropdownItem, color: "red" }}
                onClick={handleLogout}
              >
                Cerrar Sesión
              </button>
            </div>
          )}
        </div>
      </nav>

      {showLogin && (
        <InicioSesion
          onLogin={handleLoginSuccess}
          onClose={handleCloseLogin}
        />
      )}
    </>
  );
};

export default Navbar;
